+          validation_commands_run: validationCommands,
+        };
+        continue;
+      }
+      throw error;
+    }
     lastReview.validation_commands_run = validationCommands;
     if (isCleanCodexReview(lastReview)) return lastReview;
     if (attempt === maxReviewAttempts) break;
